const records = $json.records || [];
const syncRunId = $json.sync_run_id || null;

if (records.length === 0) {
  return [
    {
      json: {
        __empty_batch: true,
        count: 0,
        records: [],
        sync_run_id: syncRunId
      }
    }
  ];
}

return records.map(record => ({
  json: {
    ...record,
    sync_run_id: syncRunId
  }
}));

const syncRunId =
  $json.sync_run_id ??
  $("Postgres Create Sync Run").first().json.sync_run_id ??
  null;

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: 0,
      staged_count: 0,
      promoted_count: 0,
      skipped_count: 0,
      error_count: 0
    }
  }
];

const ledgerItems = [];
const vendorItems = [];

for (const item of $input.all()) {
  const pg = item.json.parent_group || '';
  if (pg.trim() === 'Sundry Creditors') {
    vendorItems.push(item);
  } else {
    ledgerItems.push(item);
  }
}

// Return ledger items on output 0, vendor items on output 1
// n8n Code node only supports one output, so we return both with a type marker
const out = [];
for (const i of ledgerItems) {
  out.push({ json: { ...i.json, __entity_type: 'ledger' } });
}
for (const i of vendorItems) {
  out.push({ json: { ...i.json, __entity_type: 'vendor' } });
}
return out;

const out = [];
for (const item of $input.all()) {
  const row = item.json;
  const gst = row.gst_details || {};
  const sourceHash = [
    row.erp_sync_id ?? '',
    row.ledger_code ?? '',
    row.name ?? '',
    row.account_type ?? '',
    row.parent_group ?? '',
    gst.party_gstin ?? '',
    gst.gst_registration_type ?? '',
    gst.income_tax_number ?? '',
    gst.is_billwise_on ?? ''
  ].join('|');
  out.push({ json: { ...row, source_hash: sourceHash } });
}
return out;

// Safe value extractor: handles null, object with #text, array, plain string
function tv(val) {
  if (val === null || val === undefined) return null;
  if (Array.isArray(val)) {
    const parts = val.map(tv).filter(v => v !== null && v !== '');
    return parts.length > 0 ? parts.join(', ') : null;
  }
  if (typeof val === 'object') {
    if ('#text' in val) {
      const t = String(val['#text']).trim();
      return t === '' ? null : t;
    }
    return null;
  }
  const s = String(val).trim();
  return s === '' ? null : s;
}

// Address flattener: supports ADDRESS.LIST shapes
function extractAddress(addrList) {
  if (addrList === null || addrList === undefined) return null;
  if (typeof addrList === 'string') {
    const s = addrList.trim();
    return s === '' ? null : s;
  }
  if (Array.isArray(addrList)) {
    const parts = addrList.map(a => {
      if (typeof a === 'object' && a !== null) {
        return tv(a['ADDRESS']) ?? tv(a['#text']) ?? null;
      }
      return tv(a);
    }).filter(v => v !== null && v !== '');
    return parts.length > 0 ? parts.join(', ') : null;
  }
  if (typeof addrList === 'object') {
    const inner = addrList['ADDRESS'];
    if (inner !== undefined) {
      if (Array.isArray(inner)) {
        const parts = inner.map(tv).filter(v => v !== null && v !== '');
        return parts.length > 0 ? parts.join(', ') : null;
      }
      return tv(inner);
    }
    return tv(addrList['#text']) ?? null;
  }
  return null;
}

const out = [];
for (const item of $input.all()) {
  const row = item.json;
  const gst = row.gst_details || {};
  const raw = row.raw_payload || {};

  const vendorCode = null;

  // gstin: prefer raw PARTYGSTIN, fall back to gst_details
  const gstin = tv(raw['PARTYGSTIN']) ?? tv(gst.party_gstin) ?? null;

  // tax_id from INCOMETAXNUMBER in raw payload first, then gst_details
  const taxId = tv(raw['INCOMETAXNUMBER']) ?? tv(gst.income_tax_number) ?? null;

  const underGroup = row.parent_group ?? null;
  const tallyLedgerName = row.name ?? null;

  const address =   extractAddress(raw['ADDRESS.LIST'])?.replace(/,/g, ' ') ?? null;
  const pincode = tv(raw['PINCODE']);
  const state = tv(raw['LEDGERSTATENAME']);
  const phone   = tv(raw['LEDGERPHONE']);
  const email   = tv(raw['EMAIL']);

  const sourceHash = [
    row.erp_sync_id ?? '',
    vendorCode ?? '',
    row.name ?? '',
    gstin ?? '',
    taxId ?? '',
    underGroup ?? '',
    state ?? '',
    address ?? '',
    '',
    '',
    pincode ?? '',
    phone ?? '',
    email ?? '',
    tallyLedgerName ?? '',
    ''
  ].join('|');

  out.push({
    json: {
      sync_run_id: row.sync_run_id,
      erp_sync_id: row.erp_sync_id,
      vendor_code: vendorCode,
      name: row.name ?? null,
      gstin: gstin,
      tax_id: taxId,
      under_group: underGroup,
      state: state,
      address: address,
      pan: null,
      city: null,
      pincode: pincode,
      phone: phone,
      email: email,
      tally_ledger_name: tallyLedgerName,
      alias: null,
      source_hash: sourceHash,
      raw_payload: raw
    }
  });
}
return out;

// Safe success join: collect whatever arrived (ledger success, vendor success, or both)
// Pass through the first item found - sync_run_id will be injected by the final merge
const items = $input.all();
if (items.length === 0) {
  return [{ json: { __success_branch: true } }];
}
return items.map(i => ({ json: { ...i.json, __success_branch: true } }));

const allItems = $input.all();

const syncRunItem = allItems.find(i => i.json.sync_run_id !== undefined);
const syncRunId = syncRunItem?.json?.sync_run_id ?? null;

const fetchedCount = Number($("HTTP Request").first().json.count || 0);

const ledgerStaged = (() => { try { return $("Postgres Raw Stage Ledgers").all().length; } catch(e) { return 0; } })();
const vendorStaged = (() => { try { return $("Postgres Raw Stage Vendors").all().length; } catch(e) { return 0; } })();
const stagedCount = ledgerStaged + vendorStaged;

const ledgerPromoted = (() => {
  try {
    return $("Postgres Promote Ledgers").all().filter(item => {
      const j = item.json || {};
      return !!(j.id || j.erp_sync_id || j.name);
    }).length;
  } catch(e) { return 0; }
})();

const vendorPromoted = (() => {
  try {
    return $("Postgres Promote Vendors").all().filter(item => {
      const j = item.json || {};
      return !!(j.id || j.erp_sync_id || j.name);
    }).length;
  } catch(e) { return 0; }
})();

const promotedCount = ledgerPromoted + vendorPromoted;
const skippedCount = Math.max(fetchedCount - promotedCount, 0);

return [
  {
    json: {
      sync_run_id: syncRunId,
      run_status: "success",
      fetched_count: fetchedCount,
      staged_count: stagedCount,
      promoted_count: promotedCount,
      skipped_count: skippedCount,
      error_count: 0
    }
  }
];
